-- 0008_open_brewery_db_breadth.sql
-- Broadens the cold-start map/radar and regional guide layer with real Open Brewery DB rows.
-- Source: Open Brewery DB docs/FAQ. Bounded fetch: 12 breweries per U.S. state and 16 per target country, mappable rows only.

on conflict (id) do update
set name = excluded.name,
    source_kind = excluded.source_kind,
    license = excluded.license,
    homepage_url = excluded.homepage_url,
    ingest_cadence = excluded.ingest_cadence,
    notes = excluded.notes,
    updated_at = now();

create table if not exists open_brewery_db_seed_import (
  obdb_id text primary key,
  name text not null,
  brewery_type text,
  address text,
  city text,
  region text,
  postal_code text,
  country text,
  latitude numeric(10,7) not null,
  longitude numeric(10,7) not null,
  phone text,
  website_url text,
  imported_at timestamptz not null default now(),
  check (brewery_type is null or brewery_type not in ('closed', 'planning'))
);

alter table open_brewery_db_seed_import enable row level security;
revoke all on open_brewery_db_seed_import from anon, authenticated;
grant select, insert, update, delete on open_brewery_db_seed_import to service_role;

create unique index if not exists venue_open_brewery_db_unique
on venue ((external_ids->>'open_brewery_db'))
where external_ids ? 'open_brewery_db';

create unique index if not exists brewery_open_brewery_db_unique
on brewery ((external_ids->>'open_brewery_db'))
where external_ids ? 'open_brewery_db';

create or replace function apply_open_brewery_db_import()
returns table (
  breweries_inserted int,
  breweries_updated int,
  venues_inserted int,
  venues_updated int,
  source_links_written int
)
language sql
volatile
security definer
set search_path = public
as $$
  with normalized as (
    select *
    from open_brewery_db_seed_import
    where name is not null and latitude is not null and longitude is not null
      and coalesce(brewery_type, '') not in ('closed', 'planning')
  ), inserted_breweries as (
    select
      n.name,
      n.country,
      n.website_url,
      jsonb_strip_nulls(jsonb_build_object(
        'open_brewery_db', n.obdb_id,
        'brewery_type', n.brewery_type,
        'address', n.address,
        'city', n.city,
        'region', n.region,
        'postal_code', n.postal_code,
        'country', n.country,
        'phone', n.phone,
        'website_url', n.website_url,
        'source_note', 'Open Brewery DB'
      ))
    from normalized n
    where not exists (
      select 1 from brewery b where b.external_ids->>'open_brewery_db' = n.obdb_id
    )
    returning id, external_ids
  ), updated_breweries as (
    update brewery b
    set name = n.name,
        country = n.country,
        website_url = coalesce(n.website_url, b.website_url),
        external_ids = b.external_ids || jsonb_strip_nulls(jsonb_build_object(
          'brewery_type', n.brewery_type,
          'address', n.address,
          'city', n.city,
          'region', n.region,
          'postal_code', n.postal_code,
          'country', n.country,
          'phone', n.phone,
          'website_url', n.website_url,
          'source_note', 'Open Brewery DB'
        )),
        updated_at = now()
    from normalized n
    where b.external_ids->>'open_brewery_db' = n.obdb_id
    returning b.id, b.external_ids
  ), inserted_venues as (
    select
      n.name,
      case when n.brewery_type = 'bar' then 'bar' else 'brewery' end,
      'on_premise'::on_off_premise,
      st_setsrid(st_makepoint(n.longitude, n.latitude), 4326)::geography,
      lower(replace(coalesce(n.country, 'global'), ' ', '-')) || ':' || lower(replace(coalesce(n.region, 'region'), ' ', '-')),
      jsonb_strip_nulls(jsonb_build_object(
        'open_brewery_db', n.obdb_id,
        'city', n.city,
        'region', n.region,
        'country', n.country,
        'brewery_type', n.brewery_type,
        'address', n.address,
        'postal_code', n.postal_code,
        'phone', n.phone,
        'website_url', n.website_url,
        'source_note', 'Open Brewery DB'
      ))
    from normalized n
    where not exists (
      select 1 from venue v where v.external_ids->>'open_brewery_db' = n.obdb_id
    )
    returning id, external_ids
  ), updated_venues as (
    update venue v
    set name = n.name,
        poi_category = case when n.brewery_type = 'bar' then 'bar' else 'brewery' end,
        geo = st_setsrid(st_makepoint(n.longitude, n.latitude), 4326)::geography,
        geo_bucket_h3 = lower(replace(coalesce(n.country, 'global'), ' ', '-')) || ':' || lower(replace(coalesce(n.region, 'region'), ' ', '-')),
        external_ids = v.external_ids || jsonb_strip_nulls(jsonb_build_object(
          'city', n.city,
          'region', n.region,
          'country', n.country,
          'brewery_type', n.brewery_type,
          'address', n.address,
          'postal_code', n.postal_code,
          'phone', n.phone,
          'website_url', n.website_url,
          'source_note', 'Open Brewery DB'
        )),
        updated_at = now()
    from normalized n
    where v.external_ids->>'open_brewery_db' = n.obdb_id
    returning v.id, v.external_ids
  ), all_venues as (
    select id, external_ids from inserted_venues
    union all
    select id, external_ids from updated_venues
  ), links as (
    select
      'open_brewery_db',
      'venue',
      av.id,
      av.external_ids->>'open_brewery_db',
      'https://api.openbrewerydb.org/v1/breweries/' || (av.external_ids->>'open_brewery_db'),
      0.930,
      av.external_ids,
      now()
    from all_venues av
    where av.external_ids ? 'open_brewery_db'
    on conflict (source_id, object_type, object_id, external_id) do update
    set external_url = excluded.external_url,
        confidence = excluded.confidence,
        payload = excluded.payload,
        last_seen_at = now()
    returning 1
  )
  select
    (select count(*)::int from inserted_breweries),
    (select count(*)::int from updated_breweries),
    (select count(*)::int from inserted_venues),
    (select count(*)::int from updated_venues),
    (select count(*)::int from links);
$$;

revoke execute on function apply_open_brewery_db_import() from public, anon, authenticated;
grant execute on function apply_open_brewery_db_import() to service_role;

on conflict (obdb_id) do update
set name = excluded.name,
    brewery_type = excluded.brewery_type,
    address = excluded.address,
    city = excluded.city,
    region = excluded.region,
    postal_code = excluded.postal_code,
    country = excluded.country,
    latitude = excluded.latitude,
    longitude = excluded.longitude,
    phone = excluded.phone,
    website_url = excluded.website_url,
    imported_at = now();

